using System.Collections.Generic;
using UnityEngine;

/// <summary>
/// Infraestrutura de localização (multi-idioma) para o jogo Animals.
///
/// <b>Estado actual:</b> apenas Português está implementado. Os outros idiomas
/// (<see cref="GameLanguage.English"/>, Espanhol, Francês, Japonês) têm os seus
/// dicionários criados mas vazios — ao serem preenchidos e marcados como disponíveis
/// em <see cref="GameSettings.IsLanguageAvailable"/>, o seletor de idioma passa a
/// aceitá-los automaticamente.
///
/// <b>Como usar em scripts:</b>
/// <code>
/// string texto = LocalizationManager.Get("UI_ConfirmButton"); // → "Confirmar" / "Confirm" / …
/// </code>
///
/// <b>Como reagir a mudanças de idioma em tempo real:</b>
/// <code>
/// private void OnEnable()  => LocalizationManager.LanguageChanged += RefreshTexts;
/// private void OnDisable() => LocalizationManager.LanguageChanged -= RefreshTexts;
/// private void RefreshTexts() { myLabel.text = LocalizationManager.Get("MinhaChave"); }
/// </code>
///
/// <b>Prioridade de fallback:</b> se a chave não existir no idioma activo, tenta
/// Português; se não existir em Português, devolve a própria chave entre [ ] para
/// facilitar a detecção de strings não localizadas durante o desenvolvimento.
///
/// <b>Para adicionar um novo idioma:</b>
/// 1. Adicionar entrada em <see cref="GameLanguage"/> (GameSettings.cs).
/// 2. Marcar como available em <see cref="GameSettings.IsLanguageAvailable"/>.
/// 3. Preencher o dicionário correspondente nesta classe (bloco "Dicionários").
/// 4. Garantir suporte de fonte TMP para o charset (ver Guia_HUD_Localizacao.md).
///
/// <b>Montagem no Editor:</b> este componente segue o padrão de singleton com
/// auto-fallback — não precisa de ser colocado em cena manualmente, mas é
/// recomendado incluí-lo no GameBootstrap para controlo total das chaves.
/// </summary>
public class LocalizationManager : MonoBehaviour
{
    public static LocalizationManager Instance { get; private set; }

    /// <summary>Disparado quando o idioma muda — todos os componentes de UI com
    /// texto localizado devem subscrever e chamar o seu RefreshTexts().</summary>
    public static event System.Action LanguageChanged;

    private bool isAutoFallback;

    private void Awake()
    {
        if (Instance != null && Instance != this)
        {
            if (Instance.isAutoFallback && !isAutoFallback)
                Destroy(Instance.gameObject);
            else
            {
                Destroy(gameObject);
                return;
            }
        }

        Instance = this;
        transform.SetParent(null);
        DontDestroyOnLoad(gameObject);
    }

    [RuntimeInitializeOnLoadMethod(RuntimeInitializeLoadType.BeforeSceneLoad)]
    private static void EnsureExists()
    {
        if (Instance != null) return;
        var go = new GameObject(nameof(LocalizationManager) + " (Fallback)");
        var inst = go.AddComponent<LocalizationManager>();
        inst.isAutoFallback = true;
    }

    private void OnEnable()
    {
        if (GameSettings.Instance != null)
            GameSettings.Instance.SettingsChanged += OnSettingsChanged;
    }

    private void OnDisable()
    {
        if (GameSettings.Instance != null)
            GameSettings.Instance.SettingsChanged -= OnSettingsChanged;
    }

    private void OnSettingsChanged() => LanguageChanged?.Invoke();

    // =====================================================================
    // API Pública
    // =====================================================================

    /// <summary>
    /// Devolve o texto localizado da chave no idioma activo (GameSettings.Language).
    /// Se a chave não existir no idioma activo, tenta Português como fallback.
    /// Se não existir em Português, devolve "[chave]" para facilitar debug.
    /// </summary>
    public static string Get(string key)
    {
        if (string.IsNullOrEmpty(key)) return string.Empty;

        var lang = GameSettings.Instance != null
            ? GameSettings.Instance.Language
            : GameLanguage.Portugues;

        var dict = GetDictionary(lang);
        if (dict != null && dict.TryGetValue(key, out var value) && !string.IsNullOrEmpty(value))
            return value;

        // Fallback → Português
        var ptDict = GetDictionary(GameLanguage.Portugues);
        if (ptDict != null && ptDict.TryGetValue(key, out var ptValue) && !string.IsNullOrEmpty(ptValue))
            return ptValue;

        // Chave não encontrada — devolve a chave para debug.
        Debug.LogWarning($"[LocalizationManager] Chave não localizada: \"{key}\" (idioma: {lang})");
        return $"[{key}]";
    }

    // =====================================================================
    // Dicionários por idioma
    // =====================================================================

    private static Dictionary<string, string> GetDictionary(GameLanguage lang)
    {
        return lang switch
        {
            GameLanguage.Portugues => _pt,
            GameLanguage.English   => _en,
            GameLanguage.Espanhol  => _es,
            GameLanguage.Frances   => _fr,
            GameLanguage.Japones   => _ja,
            _ => null,
        };
    }

    // ---- Português (idioma base — OBRIGATÓRIO preencher todas as chaves aqui) ----

    private static readonly Dictionary<string, string> _pt = new()
    {
        // Geral / UI
        { "UI_Confirm",         "Confirmar" },
        { "UI_Cancel",          "Cancelar"  },
        { "UI_Back",            "Voltar"    },
        { "UI_Save",            "Guardar"   },
        { "UI_Load",            "Carregar"  },
        { "UI_Yes",             "Sim"       },
        { "UI_No",              "Não"       },

        // Menu de Pausa — Opções
        { "Options_Language",         "Idioma"            },
        { "Options_Language_Value",   "Português"         },
        { "Options_ComingSoon",       "Brevemente..."     },
        { "Options_TextSize_Small",   "Pequeno"           },
        { "Options_TextSize_Medium",  "Médio"             },
        { "Options_TextSize_Large",   "Grande"            },
        { "Options_GaiaVoice_On",     "Dublado"           },
        { "Options_GaiaVoice_Off",    "OFF"               },

        // Emblemas / Auras
        { "Aura_Apolo_Label",  "Aura de Fogo"    },
        { "Aura_Gaia_Label",   "Aura de Gaia"    },
        { "Aura_Zeus_Label",   "Aura de Zeus"    },

        // Tutoriais (exemplos — preencher ao longo do desenvolvimento)
        // { "Tutorial_WaterDanger", "Cuidado com a água!" },
    };

    // ---- English (a preencher quando a tradução estiver completa) ----

    private static readonly Dictionary<string, string> _en = new()
    {
        // Adicionar entradas aqui quando a tradução EN estiver disponível.
        // Exemplo:
        // { "UI_Confirm",        "Confirm"  },
        // { "UI_Cancel",         "Cancel"   },
        // { "Options_Language_Value", "English" },
    };

    // ---- Español ----

    private static readonly Dictionary<string, string> _es = new()
    {
        // A preencher quando a tradução ES estiver disponível.
    };

    // ---- Français ----

    private static readonly Dictionary<string, string> _fr = new()
    {
        // A preencher quando a tradução FR estiver disponível.
    };

    // ---- 日本語 ----
    // NOTA: requer fonte TMP com suporte CJK (ex: Noto Sans JP ou similar).
    // Ver Guia_HUD_Localizacao.md para instruções de configuração de fonte.

    private static readonly Dictionary<string, string> _ja = new()
    {
        // A preencher quando a tradução JA estiver disponível.
    };
}
